package github.chains;

import spoon.Launcher;
import spoon.reflect.CtModel;
import spoon.reflect.code.CtExpression;
import spoon.reflect.code.CtInvocation;
import spoon.reflect.declaration.CtMethod;
import spoon.reflect.declaration.CtType;
import spoon.reflect.reference.CtExecutableReference;
import spoon.reflect.visitor.filter.TypeFilter;

import java.util.List;

/**
 * Generic transformation rule to fix Maven dependency tree API breaking changes.
 * This transformation fixes calls to buildDependencyGraph(MavenProject, ArtifactFilter) 
 * that should now use buildDependencyGraph(ProjectBuildingRequest, ArtifactFilter)
 */
public class Main {
    public static void main(String[] args) {
        // This is a generic transformation that can be applied to any Maven project
        // with the same API breaking change
        Launcher launcher = new Launcher();
        launcher.setArgs(new String[]{
            "--output-type", "nooutput",
            "--source-classpath", "/workspace/license-maven-plugin/license-maven-plugin/target/classes"
        });

        // Add the source directory to be analyzed
        launcher.addInputResource("/workspace/license-maven-plugin/license-maven-plugin/src/main/java");

        // Process the model
        CtModel model = launcher.buildModel();

        // Find all invocations of buildDependencyGraph with wrong signature
        List<CtInvocation> invocations = model.getElements(new TypeFilter<>(CtInvocation.class) {
            @Override
            public boolean matches(CtInvocation element) {
                // Match method calls to buildDependencyGraph with 2 parameters
                CtExecutableReference<?> executableRef = element.getExecutable();
                if (executableRef == null) return false;

                // Look for the specific method signature in the dependency graph builder
                return executableRef.getSimpleName().equals("buildDependencyGraph") &&
                       element.getArguments().size() == 2;
            }
        });

        // Apply the transformation to fix the API calls
        for (CtInvocation invocation : invocations) {
            // Get the method being called
            CtExecutableReference<?> executableRef = invocation.getExecutable();
            if (executableRef == null) continue;

            // Check if it's the problematic method signature
            // The old signature was: buildDependencyGraph(MavenProject, ArtifactFilter)
            // The new signature is: buildDependencyGraph(ProjectBuildingRequest, ArtifactFilter)

            // Get the first argument (should be MavenProject in old version)
            CtExpression<?> firstArg = invocation.getArguments().get(0);

            // Create a new invocation that uses the buildingRequest
            // This requires more complex logic to properly fix this
            // For now, we'll just print what we found
            System.out.println("Found problematic invocation: " + invocation.toString());
        }

        System.out.println("Transformation completed");
    }
}

