package github.chains;

import spoon.Launcher;
import spoon.reflect.CtModel;
import spoon.reflect.code.CtExpression;
import spoon.reflect.code.CtInvocation;
import spoon.reflect.code.CtLiteral;
import spoon.reflect.code.CtStatement;
import spoon.reflect.code.CtThisAccess;
import spoon.reflect.declaration.CtClass;
import spoon.reflect.declaration.CtField;
import spoon.reflect.declaration.CtMethod;
import spoon.reflect.reference.CtExecutableReference;
import spoon.reflect.visitor.filter.TypeFilter;

import java.util.List;

/**
 * Generic transformation rule to fix Maven dependency tree API breaking changes.
 * This fixes calls to buildDependencyGraph(MavenProject, ArtifactFilter) 
 * that should now use buildDependencyGraph(ProjectBuildingRequest, ArtifactFilter)
 * by replacing the MavenProject argument with the buildingRequest field access.
 */
public class Main {
    public static void main(String[] args) {
        // Run spoon transformation on the license-maven-plugin project
        Launcher launcher = new Launcher();
        launcher.setArgs(new String[]{
            "--output-type", "nooutput"
        });

        // Add the source directory to be analyzed
        launcher.addInputResource("/workspace/license-maven-plugin/license-maven-plugin/src/main/java");

        // Process the model
        CtModel model = launcher.buildModel();

        // Find the specific class that has the problematic method call
        List<CtClass<?>> classes = model.getElements(new TypeFilter<>(CtClass.class) {
            @Override
            public boolean matches(CtClass<?> element) {
                return "MavenProjectLicenses".equals(element.getSimpleName());
            }
        });

        if (classes.isEmpty()) {
            System.out.println("Could not find MavenProjectLicenses class");
            return;
        }

        CtClass<?> mavenProjectLicensesClass = classes.get(0);

        // Find all invocations of buildDependencyGraph with 2 parameters (the problematic ones)
        List<CtInvocation> invocations = model.getElements(new TypeFilter<>(CtInvocation.class) {
            @Override
            public boolean matches(CtInvocation element) {
                CtExecutableReference<?> executableRef = element.getExecutable();
                if (executableRef == null) return false;

                // Look for the specific method signature in the dependency graph builder
                return executableRef.getSimpleName().equals("buildDependencyGraph") &&
                       element.getArguments().size() == 2;
            }
        });

        // Apply the transformation to fix the API calls
        for (CtInvocation invocation : invocations) {
            // Ensure this is the specific problematic call in getDependencies method
            if (isInGetDependenciesMethod(invocation, mavenProjectLicensesClass)) {
                System.out.println("Found problematic buildDependencyGraph call: " + invocation.toString());

                // Replace the first argument (MavenProject) with buildingRequest
                CtExpression<?> firstArg = invocation.getArguments().get(0);
                CtThisAccess<?> thisAccess = invocation.getFactory().createThisAccess(
                    invocation.getFactory().createTypeReference(Object.class));

                // Create the reference to buildingRequest field
                CtExpression<?> buildingRequestAccess = invocation.getFactory().createFieldRead(
                    thisAccess, 
                    mavenProjectLicensesClass.getField("buildingRequest")
                );

                // Replace the first argument
                invocation.getArguments().set(0, buildingRequestAccess);
                System.out.println("Fixed the call to use buildingRequest instead of project");
            }
        }

        System.out.println("Transformation analysis completed");
    }

    private static boolean isInGetDependenciesMethod(CtInvocation invocation, CtClass<?> clazz) {
        // Find the getDependencies method
        List<CtMethod> methods = clazz.getMethodsByName("getDependencies");
        if (methods.isEmpty()) {
            return false;
        }

        CtMethod getDependenciesMethod = methods.get(0);
        // Check if the invocation is within the getDependencies method body
        return getDependenciesMethod.getBody().getStatements().contains(invocation);
    }
}

